import * as Haptics from 'expo-haptics'
import { useSettingsStore } from '../store/settingsStore'

export function useHaptics() {
  const enabled = useSettingsStore(s => s.hapticsEnabled)
  return {
    impactLight:          () => enabled && Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light),
    impactHeavy:          () => enabled && Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Heavy),
    notificationSuccess:  () => enabled && Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success),
    notificationError:    () => enabled && Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error),
  }
}

const shakeX = useRef(new Animated.Value(0)).current
function triggerShake() {
  Animated.sequence([
    Animated.timing(shakeX, { toValue: -8, duration: 50, useNativeDriver: true }),
    Animated.timing(shakeX, { toValue:  8, duration: 50, useNativeDriver: true }),
    Animated.timing(shakeX, { toValue: -4, duration: 40, useNativeDriver: true }),
    Animated.timing(shakeX, { toValue:  0, duration: 40, useNativeDriver: true }),
  ]).start()
}
